import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "以 Claude Design 级别的质量做设计，却不烧 token",
    summary: "一份以成本为先的 Open Design 指南——摆脱 token 上限，把设计工作交给你已经付费的那个智能体（或你自己的密钥）来跑，构建一个完整的落地页，甚至生成一段视频，然后部署。还有一段坦诚的「何时该用哪个工具」的判断。基于 Roy Shavit 的实操演示。",
    bodyHtml: "<p>本指南正面切入成本问题：如果你用过封闭式云端设计工具，你就懂那种神奇——也知道 token 耗得有多快。Open Design 让你能以相近的质量做设计，因为它把工作交给<strong>任何你想用的模型</strong>来跑——你已经付费的那个智能体，或者你自己的密钥——这样你就不必再为一份单独的设计预算精打细算。它沿用 <strong>Roy Shavit</strong> 在<a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">他的实操演示</a>中跑的那套构建流程，用英文重写并更新到了当前版本。想看实时演示就看上方视频，想看文字版就继续往下读。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"Open Design 中的 HyperFrames 动效与视频画廊。\">\n<em>HyperFrames 画廊：由代码驱动的动效与视频作品，你可以复刻并二次创作。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台。和那款封闭式云端工具一样，你给它一个提示词，就能拿回一个真实的成品——落地页、应用或幻灯片——以可编辑的 HTML 形式呈现，你可以在 VS Code 或你的编辑器里继续打磨。有三点让它与众不同，而前两点正是它运行成本更低的原因：</p>\n<ul>\n<li><strong>它是开源的（Apache-2.0）</strong>——你可以读源码、fork 它、自托管它。</li>\n<li><strong>它在你的电脑上运行</strong>——文件留在你自己的机器上；没有任何东西上传到第三方云端。</li>\n<li><strong>它能用任何你想用的模型</strong>——通过你现有的 CLI，使用 Codex、Claude，或其他 15 种以上的模型，又或者用你自己的 API 密钥（BYOK）。</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">成本这件事：别再精打细算 token 了</h2>\n<p>Roy 的说法直白，而这正是关键所在：封闭式云端设计工具会很快烧光它的 token 额度，于是你不得不省着用，处处节制自己的设计工作。Open Design 移除了这个天花板，因为<strong>生成是通过你已经拥有的智能体／订阅，或一把你自己掌控的密钥来跑的。</strong>你可以为每个项目自行决定成本／质量的权衡——草稿用便宜的模型，定稿那一遍用顶级模型——而不是被别人那份单独的设计额度计量着用。自托管还意味着工作发生在你自己的机器上，这让一切都更精简。</p>\n<h2 id=\"step-1--install-and-detect-your-models\">第 1 步——安装并检测你的模型</h2>\n<p>最简单的路径是<strong>桌面应用</strong>：访问 <a href=\"https://open-design.ai/download\">open-design.ai/download</a>，选择你的操作系统，下载，然后把它拖进去。更喜欢从源码安装：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>打开它打印出的本地 URL（一个动态端口——不要写死）。在设置里，Open Design 会<strong>立即识别本地已安装的模型</strong>——Roy 装了 Codex 和 Claude，它也会识别出 OpenCode 或其他模型。设一个默认模型，或者从任意供应商带上你自己的密钥，这样你甚至都不需要装 CLI。这正是它的独特之处：你不会被绑死在某一家供应商上。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"Open Design 的幻灯片模式，附带示例演示文稿。\">\n<em>幻灯片模式：选择一个演示文稿类别，并以一个示例为起点进行复刻。</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">第 2 步——构建一个落地页，低成本迭代</h2>\n<p>Roy 为一项游戏串流服务构建了一个落地页。他发出需求简述，Open Design 返回一份<strong>探索表单</strong>（产出类型、受众、品牌方向、范围、动效程度），他作答后，它就开始构建——这里跑的是 Claude Opus，因为他的 CLI 就设成了这个。结果是一个扎实的初版：主视觉区、演示数据、平台支持、定价页、用户评价、常见问题——在桌面、平板和手机上都做了响应式适配。</p>\n<p>这些迭代工具让改动的成本保持很低：<strong>选中一块区域并加上批注</strong>、留一条评论，或者做<strong>行内编辑</strong>直接改文字。切到<strong>代码</strong>视图就能看到生成的 HTML 和设计文件。满意之后，<strong>分享</strong>按钮可以导出为 PDF，或者直接部署到 <strong>Vercel 或 Cloudflare Pages</strong>（填入你的 token，站点就上线了），又或者你点进源码，在 VS Code、Cursor 或你的编辑器里继续干活。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"在 Open Design 中生成的真实原型。\">\n<em>在预览中呈现的真实生成原型——一个深色、富有电影感的代理公司落地页。</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">第 3 步——超越页面：生成一段视频</h2>\n<p>Open Design 并不局限于静态设计。Roy 用 <strong>hyperframes</strong> 动效技能生成了一段《纽约时报》风格的动态条形图——花了几分钟，产出一个真实的 MP4，你可以把它放进一段更长的视频里，或者当作一段带品牌的片段来用。还有 170 多个设计系统插件可供选择（Apple、PlayStation 等等），而且因为这个库是开放的，社区还在不断往里添东西。</p>\n<h2 id=\"when-to-use-which-the-honest-call\">何时该用哪个（坦诚的判断）</h2>\n<p>Roy 说得很公道。当你想要模型的灵活性、更低的成本或自托管时，选 <strong>Open Design</strong>——工作留在你自己的机器上，跑在你选的任何模型上，包括第三方模型。当你想要一套最简、零安装的配置，并以最少的工作量上手时，选那款<strong>封闭式云端工具</strong>——而且要说明，它开箱即用的成品仍然要更精致一点。同样的内容，那边完成度略高；而这边的掌控力明显更强、运行成本更低。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>跑在你已经付费的那个智能体上</strong>（或 BYOK），以摆脱一份单独的 token 上限。</li>\n<li><strong>草稿用便宜的模型，定稿用强力的模型</strong>——你可以为每个项目调节成本／质量这个旋钮。</li>\n<li><strong>用行内编辑和区域批注</strong>来做廉价、精准的改动，而不是整页重新生成。</li>\n<li><strong>导出为代码，或部署到 Vercel／Cloudflare</strong>——做完后直接从分享里操作。</li>\n<li><strong>试试 hyperframes 技能</strong>——当你需要动效／视频，而不只是静态页面时。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>相比封闭式云端工具，这是怎么省下 token 的？</strong>\n生成是通过你自己的智能体／订阅，或你自己的 API 密钥来跑的，所以没有一份单独的、被计量的设计预算需要耗尽——模型和成本都由你来选。</p>\n<p><strong>我能在自己的编辑器里继续打磨产出吗？</strong>\n可以——产出是可编辑的 HTML／文件。点进源码，在 VS Code、Cursor 或任何编辑器里继续，或者部署到 Vercel／Cloudflare Pages。</p>\n<p><strong>它能做的不止网页吗？</strong>\n是的——原型、幻灯片、图片和视频（通过 hyperframes 动效技能），外加一个庞大的设计系统库。</p>\n<p><strong>它免费吗？</strong>\n这个应用在 Apache-2.0 协议下开源，本地运行免费。你只需为你接入的那个智能体和密钥所产生的模型与媒体用量付费。</p>\n<hr>\n<p><em>这份文字指南基于 Roy Shavit 的实操演示。请观看上方的完整视频，并<a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">订阅 Roy Shavit</a>，获取更多实用的 AI 构建内容。</em></p>",
  },
  "ja": {
    title: "トークンを浪費せずに Claude Design 並みの品質でデザインする",
    summary: "コストを最優先にした Open Design ガイド。すでに料金を払っているエージェント（または自分のキー）でデザインを動かしてトークンの上限から抜け出し、完全なランディングページを作り、動画まで生成して、デプロイする。さらに「どんなときにどのツールを使うか」という率直な判断も。Roy Shavit のウォークスルーに基づく。",
    bodyHtml: "<p>このガイドはコストの観点に正面から切り込む。クローズドなクラウド型デザインツールを使ったことがあるなら、その魔法はわかるはずだ——そして、トークンがあっという間に尽きることも。Open Design なら、作業を<strong>あなたが使いたい任意のモデル</strong>で動かせるので、同等の品質でデザインできる——すでに料金を払っているエージェントでも、自分のキーでもいい——だから、別枠のデザイン予算をやりくりする必要がない。<strong>Roy Shavit</strong> が<a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">彼のウォークスルー</a>で実演している構築の流れを、英語で書き直し、現行リリースに合わせて最新化したものだ。ライブの実演は上の動画を、文章版は以下を読み進めてほしい。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"Open Design の HyperFrames モーション・動画ギャラリー。\">\n<em>HyperFrames ギャラリー：コード駆動のモーションや動画作品を、フォークしてリミックスできます。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは？</h2>\n<p>Open Design は、オープンソースでローカルファーストのデザインプラットフォームだ。あのクローズドなクラウド型ツールと同じく、プロンプトを与えると本物の成果物——ランディングページ、アプリ、デッキ——が、VS Code や自分のエディタで作業を続けられる編集可能な HTML として返ってくる。これを際立たせる点が 3 つあり、最初の 2 つが、より低コストで動かせる理由だ：</p>\n<ul>\n<li><strong>オープンソースである（Apache-2.0）</strong>——コードを読み、フォークし、セルフホストできる。</li>\n<li><strong>自分のコンピュータ上で動く</strong>——ファイルは自分のマシンに留まり、サードパーティのクラウドには何も送られない。</li>\n<li><strong>使いたい任意のモデルを使える</strong>——既存の CLI 経由で Codex、Claude、あるいは 15 種類以上の他のモデルを、または自分の API キー（BYOK）を。</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">コストの話：トークンのやりくりをやめよう</h2>\n<p>Roy の言い方はストレートで、それこそが核心だ。クローズドなクラウド型デザインツールは割り当てられたトークンを非常に速く使い切るので、結局はデザイン作業を切り詰めることになる。Open Design はその上限を取り払う。なぜなら<strong>生成は、すでに持っているエージェント／サブスクリプション、あるいは自分が管理するキーを通して動くからだ。</strong>コストと品質のトレードオフはプロジェクトごとに自分で決める——下書きには安いモデル、最終仕上げにはトップモデル——他人の別枠のデザイン上限で計量されるのではなく。セルフホストはまた、作業が自分のマシン上で行われることを意味し、それが全体をスリムに保つ。</p>\n<h2 id=\"step-1--install-and-detect-your-models\">ステップ 1——インストールしてモデルを検出する</h2>\n<p>いちばん簡単なのは<strong>デスクトップアプリ</strong>だ：<a href=\"https://open-design.ai/download\">open-design.ai/download</a> にアクセスし、OS を選び、ダウンロードして、ドラッグして入れる。ソースから入れたいなら：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>表示されるローカル URL を開く（動的なポートなので、ハードコードしないこと）。設定画面で、Open Design は<strong>ローカルにインストールされたモデルを即座に認識する</strong>——Roy は Codex と Claude を入れていて、OpenCode やその他も拾い上げるはずだ。デフォルトを設定するか、任意のプロバイダーから自分のキーを持ち込めば、CLI をインストールする必要すらない。これこそが独自性だ：ひとつのベンダーに縛られない。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"Open Design のスライドデッキモードと、サンプルデッキ。\">\n<em>スライドデッキモード：デッキのカテゴリを選び、サンプルをフォークして出発点にします。</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">ステップ 2——ランディングページを作り、安く反復する</h2>\n<p>Roy はゲームストリーミングサービスのランディングページを作る。要件を送ると、Open Design は<strong>ディスカバリーフォーム</strong>（出力タイプ、ターゲット層、ブランドの方向性、スコープ、モーションの度合い）を返してくる。彼が回答すると、それを構築する——ここでは Claude Opus で動いている。彼の CLI がそう設定されているからだ。結果は、しっかりした初版だ：ヒーロー、デモの数字、対応プラットフォーム、料金ページ、利用者の声、FAQ——デスクトップ、タブレット、スマホにレスポンシブ対応している。</p>\n<p>反復ツールは変更のコストを低く抑える：<strong>範囲を選んでメモを添える</strong>、コメントを残す、あるいは<strong>インライン編集</strong>でテキストを直接書き換える。<strong>コード</strong>ビューに切り替えれば、生成された HTML とデザインファイルが見られる。満足したら、<strong>共有</strong>ボタンで PDF に書き出すか、<strong>Vercel または Cloudflare Pages</strong> に直接デプロイする（トークンを入れればサイトが公開される）。あるいはソースへ進んで、VS Code、Cursor、または自分のエディタで作業を続ける。</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Open Design で生成された実際のプロトタイプ。\">\n<em>プレビューに表示された実際の生成プロトタイプ——ダークで映画的なエージェンシーのランディングページ。</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">ステップ 3——ページを超えて：動画を生成する</h2>\n<p>Open Design は静的なデザインに限られない。Roy は <strong>hyperframes</strong> のモーションスキルを使って、ニューヨーク・タイムズ風のアニメーション棒グラフを生成する——数分で本物の MP4 ができ、長めの動画に入れたり、ブランド入りのスニペットとして使ったりできる。選べるデザインシステムプラグインも 170 種類以上ある（Apple、PlayStation など）。そしてライブラリはオープンなので、コミュニティが追加を続けている。</p>\n<h2 id=\"when-to-use-which-the-honest-call\">どんなときにどちらを使うか（率直な判断）</h2>\n<p>Roy はそこをフェアに語る。モデルの柔軟性、より低いコスト、あるいはセルフホストが欲しいときは <strong>Open Design</strong> に手を伸ばそう——作業は自分のマシンに留まり、選んだ任意のモデル（サードパーティ製を含む）で動く。最小限でインストール不要のセットアップと、始めるまでの手間が最も少ないことを求めるなら、<strong>クローズドなクラウド型ツール</strong>に手を伸ばそう——そして、こちらは依然として最初から少しだけ洗練されている点に留意してほしい。同じ内容でも、あちらの方が仕上がりがわずかに高い。こちらは、はるかに高いコントロールと低い運用コストがある。</p>\n<h2 id=\"tips\">ヒント</h2>\n<ul>\n<li><strong>すでに料金を払っているエージェントで動かす</strong>（または BYOK）ことで、別枠のトークン上限から抜け出す。</li>\n<li><strong>下書きは安いモデルで、仕上げは強力なモデルで</strong>——コストと品質のダイヤルをプロジェクトごとに自分で握る。</li>\n<li><strong>インライン編集と範囲コメントを使う</strong>——全体を再生成するのではなく、安く外科的な変更を。</li>\n<li><strong>コードに書き出すか、Vercel／Cloudflare にデプロイする</strong>——終わったら共有から直接。</li>\n<li><strong>hyperframes スキルを試す</strong>——静的なページだけでなく、モーションや動画が必要なときに。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>クローズドなクラウド型ツールと比べて、これはどうやってトークンを節約するの？</strong>\n生成は自分のエージェント／サブスクリプション、または自分の API キーを通して動くので、使い切るべき別枠の計量されたデザイン予算がない——モデルもコストも自分で選ぶ。</p>\n<p><strong>出力を自分のエディタで作業し続けられる？</strong>\nはい——出力は編集可能な HTML／ファイルだ。ソースへ進んで VS Code、Cursor、または任意のエディタで続けるか、Vercel／Cloudflare Pages にデプロイできる。</p>\n<p><strong>ウェブページ以外も作れる？</strong>\nはい——プロトタイプ、デッキ、画像、動画（hyperframes のモーションスキル経由）、加えて大規模なデザインシステムのライブラリ。</p>\n<p><strong>無料なの？</strong>\nアプリは Apache-2.0 のもとでオープンソースであり、ローカルでの実行は無料だ。接続したエージェントとキーの、モデルとメディアの利用分だけを支払う。</p>\n<hr>\n<p><em>この文章ガイドは Roy Shavit のウォークスルーに基づいている。上のフル動画を見て、より実践的な AI 構築コンテンツのために <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">Roy Shavit をフォロー</a>してほしい。</em></p>",
  },
  "ko": {
    title: "토큰을 태우지 않고 Claude Design 수준의 품질로 디자인하기",
    summary: "비용을 최우선으로 다룬 Open Design 가이드 — 토큰 상한에서 벗어나, 이미 비용을 내고 있는 에이전트(또는 자신의 키)로 디자인 작업을 돌리고, 완전한 랜딩 페이지를 만들고, 영상까지 생성한 뒤 배포한다. 여기에 \"어떤 상황에서 어떤 도구를 쓸지\"에 대한 솔직한 판단까지. Roy Shavit의 실습 영상을 바탕으로 함.",
    bodyHtml: "<p>이 가이드는 비용 문제를 정면으로 다룬다. 폐쇄형 클라우드 디자인 도구를 써봤다면 그 마법을 알 것이다 — 그리고 토큰이 얼마나 빨리 바닥나는지도. Open Design은 작업을 <strong>당신이 원하는 어떤 모델</strong>로든 돌리게 해주기 때문에 비슷한 품질로 디자인할 수 있다 — 이미 비용을 내고 있는 에이전트든, 자신의 키든 — 그래서 별도의 디자인 예산을 아껴 쓸 필요가 없다. <strong>Roy Shavit</strong>이 <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">자신의 실습 영상</a>에서 진행하는 빌드 과정을 영어로 다시 쓰고 현재 릴리스에 맞춰 최신화한 것이다. 라이브 실행은 위 영상을, 글로 된 버전은 아래에서 읽으면 된다.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"Open Design의 HyperFrames 모션·비디오 갤러리.\">\n<em>HyperFrames 갤러리: 코드 기반의 모션과 비디오 작품을 포크하고 리믹스할 수 있습니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 오픈소스이자 로컬 우선의 디자인 플랫폼이다. 그 폐쇄형 클라우드 도구처럼 프롬프트를 주면 진짜 결과물 — 랜딩 페이지, 앱, 또는 덱 — 을 VS Code나 자신의 에디터에서 계속 작업할 수 있는 편집 가능한 HTML로 돌려준다. 이를 차별화하는 세 가지가 있는데, 그중 앞의 두 가지가 운영 비용이 더 저렴한 이유다:</p>\n<ul>\n<li><strong>오픈소스다(Apache-2.0)</strong> — 코드를 읽고, 포크하고, 직접 호스팅할 수 있다.</li>\n<li><strong>당신의 컴퓨터에서 실행된다</strong> — 파일은 자신의 기기에 머무르며, 어떤 것도 제3자 클라우드로 가지 않는다.</li>\n<li><strong>원하는 어떤 모델이든 사용한다</strong> — 기존 CLI를 통해 Codex, Claude, 또는 15개 이상의 다른 모델을, 혹은 자신의 API 키(BYOK)를.</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">비용 이야기: 토큰을 아껴 쓰는 일을 멈추자</h2>\n<p>Roy의 표현은 직설적이고, 그게 바로 핵심이다. 폐쇄형 클라우드 디자인 도구는 할당된 토큰을 매우 빠르게 소진하므로, 결국 디자인 작업을 아껴 쓰게 된다. Open Design은 그 천장을 없앤다. 왜냐하면 <strong>생성이 이미 보유한 에이전트/구독, 또는 당신이 통제하는 키를 통해 돌아가기 때문이다.</strong> 비용/품질의 절충은 프로젝트마다 직접 결정한다 — 초안에는 저렴한 모델을, 최종 마무리에는 최상위 모델을 — 남의 별도 디자인 상한에 의해 계량당하는 대신에. 직접 호스팅한다는 것은 또한 작업이 자신의 기기에서 일어난다는 뜻이며, 그것이 전체를 군더더기 없이 유지한다.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">1단계 — 설치하고 모델을 감지하기</h2>\n<p>가장 간단한 경로는 <strong>데스크톱 앱</strong>이다: <a href=\"https://open-design.ai/download\">open-design.ai/download</a>로 가서 OS를 고르고, 다운로드한 뒤, 끌어다 넣는다. 소스에서 설치하고 싶다면:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>출력되는 로컬 URL을 연다(동적 포트이므로 하드코딩하지 말 것). 설정에서 Open Design은 <strong>로컬에 설치된 모델을 즉시 인식한다</strong> — Roy는 Codex와 Claude를 가지고 있으며, OpenCode나 다른 것들도 잡아낼 것이다. 기본값을 설정하거나, 어느 제공업체에서든 자신의 키를 가져오면 CLI를 설치할 필요조차 없다. 이것이 독자성이다: 한 벤더에 강제로 묶이지 않는다.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"예시 덱이 포함된 Open Design의 슬라이드 덱 모드.\">\n<em>슬라이드 덱 모드: 덱 카테고리를 선택하고 예시를 포크해 시작점으로 삼으세요.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">2단계 — 랜딩 페이지를 만들고, 저렴하게 반복하기</h2>\n<p>Roy는 게임 스트리밍 서비스의 랜딩 페이지를 만든다. 요구사항을 보내면 Open Design이 <strong>디스커버리 폼</strong>(출력 유형, 대상, 브랜드 방향, 범위, 모션 수준)을 돌려주고, 그가 답하면 빌드한다 — 여기서는 그의 CLI가 그렇게 설정되어 있어 Claude Opus로 돌아간다. 결과는 탄탄한 첫 버전이다: 히어로, 데모 수치, 플랫폼 지원, 가격 페이지, 후기, FAQ — 데스크톱, 태블릿, 휴대폰에 걸쳐 반응형이다.</p>\n<p>반복 도구들은 변경 비용을 낮게 유지한다: <strong>영역을 선택하고 메모를 추가</strong>하거나, 댓글을 남기거나, <strong>인라인 편집</strong>으로 텍스트를 직접 바꾼다. <strong>코드</strong> 뷰로 전환하면 생성된 HTML과 디자인 파일을 볼 수 있다. 만족하면 <strong>공유</strong> 버튼으로 PDF로 내보내거나 <strong>Vercel 또는 Cloudflare Pages</strong>에 곧장 배포한다(토큰을 넣으면 사이트가 공개된다). 또는 소스로 넘어가 VS Code, Cursor, 또는 자신의 에디터에서 계속 작업한다.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Open Design에서 생성된 실제 프로토타입.\">\n<em>미리보기에 렌더링된 실제 생성 프로토타입 — 어둡고 영화 같은 에이전시 랜딩 페이지.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">3단계 — 페이지를 넘어: 영상 생성하기</h2>\n<p>Open Design은 정적 디자인에 국한되지 않는다. Roy는 <strong>hyperframes</strong> 모션 스킬을 사용해 뉴욕 타임스 스타일의 애니메이션 막대 차트를 생성한다 — 몇 분이 걸리고, 더 긴 영상에 넣거나 브랜드 스니펫으로 쓸 수 있는 진짜 MP4를 만들어낸다. 고를 수 있는 디자인 시스템 플러그인도 170개 이상 있고(Apple, PlayStation 등), 라이브러리가 열려 있기 때문에 커뮤니티가 계속 추가하고 있다.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">언제 무엇을 쓸지 (솔직한 판단)</h2>\n<p>Roy는 이 부분을 공정하게 말한다. 모델 유연성, 더 낮은 비용, 또는 직접 호스팅을 원할 때는 <strong>Open Design</strong>을 택하라 — 작업은 자신의 기기에 머무르고, 제3자 모델을 포함해 당신이 고른 어떤 모델로든 돌아간다. 최소한의, 설치가 필요 없는 설정과 시작하기까지 가장 적은 수고를 원할 때는 <strong>폐쇄형 클라우드 도구</strong>를 택하라 — 그리고 그쪽이 기본 상태에서 여전히 조금 더 다듬어져 있다는 점은 짚어두자. 같은 콘텐츠라도 그쪽이 마감이 약간 더 높고, 이쪽은 훨씬 더 큰 통제력과 더 낮은 운영 비용을 준다.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li><strong>이미 비용을 내고 있는 에이전트로 돌려라</strong>(또는 BYOK) — 별도의 토큰 상한에서 벗어나기 위해.</li>\n<li><strong>초안은 저렴한 모델로, 마무리는 강력한 모델로</strong> — 비용/품질 다이얼을 프로젝트마다 직접 쥔다.</li>\n<li><strong>인라인 편집과 영역 댓글을 사용하라</strong> — 전체 재생성 대신 저렴하고 정밀한 변경을 위해.</li>\n<li><strong>코드로 내보내거나 Vercel/Cloudflare에 배포하라</strong> — 끝났을 때 공유에서 곧장.</li>\n<li><strong>hyperframes 스킬을 시도하라</strong> — 정적 페이지뿐 아니라 모션/영상이 필요할 때.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>폐쇄형 클라우드 도구에 비해 이건 어떻게 토큰을 아끼나요?</strong>\n생성이 자신의 에이전트/구독, 또는 자신의 API 키를 통해 돌아가므로 소진해야 할 별도의 계량형 디자인 예산이 없다 — 모델과 비용을 직접 고른다.</p>\n<p><strong>결과물을 내 에디터에서 계속 작업할 수 있나요?</strong>\n네 — 출력은 편집 가능한 HTML/파일이다. 소스로 넘어가 VS Code, Cursor, 또는 어떤 에디터에서든 이어가거나, Vercel/Cloudflare Pages에 배포할 수 있다.</p>\n<p><strong>웹 페이지 말고 더 만들 수 있나요?</strong>\n네 — 프로토타입, 덱, 이미지, 영상(hyperframes 모션 스킬을 통해), 그리고 방대한 디자인 시스템 라이브러리.</p>\n<p><strong>무료인가요?</strong>\n앱은 Apache-2.0 하에 오픈소스이며 로컬에서 실행하는 것은 무료다. 연결한 에이전트와 키의 모델 및 미디어 사용분에 대해서만 비용을 낸다.</p>\n<hr>\n<p><em>이 글 가이드는 Roy Shavit의 실습 영상을 바탕으로 한다. 위의 전체 영상을 보고, 더 많은 실용적인 AI 빌드 콘텐츠를 위해 <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">Roy Shavit을 구독</a>하라.</em></p>",
  },
  "de": {
    title: "In Claude-Design-Qualität gestalten, ohne Tokens zu verbrennen",
    summary: "Ein kostenorientierter Leitfaden zu Open Design – entkomme dem Token-Limit, indem du die Designarbeit über den Agenten laufen lässt, für den du ohnehin schon zahlst (oder über deinen eigenen Key), baue eine komplette Landingpage, erzeuge sogar ein Video und deploye. Dazu eine ehrliche Einschätzung, „wann welches Werkzeug“ sinnvoll ist. Basierend auf dem Walkthrough von Roy Shavit.",
    bodyHtml: "<p>Dieser Leitfaden packt den Kostenaspekt direkt an: Wenn du schon ein geschlossenes Cloud-Designtool benutzt hast, kennst du die Magie – und du weißt, wie schnell die Tokens ausgehen. Open Design lässt dich in ähnlicher Qualität gestalten, indem es die Arbeit über <strong>jedes Modell deiner Wahl</strong> laufen lässt – den Agenten, für den du ohnehin schon zahlst, oder deinen eigenen Key – sodass du kein separates Design-Budget rationieren musst. Es folgt dem Build, den <strong>Roy Shavit</strong> in <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">seinem Walkthrough</a> durchgeht, ins Englische übertragen und auf den aktuellen Release gebracht. Sieh dir das Video oben für den Live-Durchlauf an oder lies weiter für die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"Die HyperFrames-Galerie für Motion und Video in Open Design.\">\n<em>Die HyperFrames-Galerie: code-getriebene Motion- und Video-Stücke, die du forken und remixen kannst.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, lokal-zuerst arbeitende Designplattform. Wie beim geschlossenen Cloud-Tool gibst du einen Prompt ein und bekommst ein echtes Artefakt zurück – eine Landingpage, App oder ein Deck – als editierbares HTML, an dem du in VS Code oder deinem Editor weiterarbeiten kannst. Drei Dinge heben es ab, und die ersten beiden sind der Grund, warum der Betrieb günstiger ist:</p>\n<ul>\n<li><strong>Es ist quelloffen (Apache-2.0)</strong> – lies den Code, forke ihn, hoste ihn selbst.</li>\n<li><strong>Es läuft auf deinem Computer</strong> – Dateien bleiben auf deiner Maschine; nichts geht in eine Drittanbieter-Cloud.</li>\n<li><strong>Es nutzt jedes Modell deiner Wahl</strong> – Codex, Claude oder über 15 weitere Modelle über deine vorhandene CLI, oder deinen eigenen API-Key (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">Die Kostengeschichte: Hör auf, Tokens zu rationieren</h2>\n<p>Roys Formulierung ist unverblümt, und genau darum geht es: Ein geschlossenes Cloud-Designtool verbraucht sein Token-Kontingent sehr schnell, sodass du am Ende deine Designarbeit rationierst. Open Design beseitigt diese Decke, weil <strong>die Generierung über den Agenten/das Abo läuft, das du bereits hast, oder über einen Key, den du kontrollierst.</strong> Du entscheidest den Kosten-Qualitäts-Kompromiss pro Projekt – ein günstiges Modell für Entwürfe, ein Top-Modell für den finalen Durchgang – statt von einer fremden, separaten Design-Obergrenze getaktet zu werden. Selbst-Hosting bedeutet außerdem, dass die Arbeit auf deiner Maschine stattfindet, was alles schlank hält.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">Schritt 1 – Installieren und deine Modelle erkennen</h2>\n<p>Der einfachste Weg ist die <strong>Desktop-App</strong>: Geh auf <a href=\"https://open-design.ai/download\">open-design.ai/download</a>, wähle dein Betriebssystem, lade sie herunter und zieh sie hinein. Lieber aus dem Quellcode:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Öffne die lokale URL, die ausgegeben wird (ein dynamischer Port – keinen fest hineincodieren). In den Einstellungen <strong>erkennt Open Design sofort die lokal installierten Modelle</strong> – Roy hat Codex und Claude, und es würde auch OpenCode oder andere aufgreifen. Lege ein Standardmodell fest oder bring deinen eigenen Key von einem beliebigen Anbieter mit, sodass du nicht einmal eine CLI installiert haben musst. Das ist die Besonderheit: Du wirst nicht zu einem einzigen Anbieter gezwungen.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"Der Folien-Modus in Open Design mit Beispiel-Decks.\">\n<em>Folien-Modus: Wähle eine Deck-Kategorie und forke ein Beispiel als Ausgangspunkt.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">Schritt 2 – Eine Landingpage bauen, günstig iterieren</h2>\n<p>Roy baut eine Landingpage für einen Game-Streaming-Dienst. Er schickt das Briefing, Open Design liefert ein <strong>Discovery-Formular</strong> zurück (Ausgabetyp, Zielgruppe, Markenrichtung, Umfang, Bewegungsgrad), er beantwortet es, und es baut – hier läuft es auf Claude Opus, weil seine CLI darauf eingestellt ist. Das Ergebnis ist eine solide erste Version: Hero, Demo-Zahlen, Plattform-Unterstützung, eine Preisseite, Testimonials, FAQ – responsiv über Desktop, Tablet und Telefon.</p>\n<p>Die Iterationswerkzeuge halten die Kosten von Änderungen niedrig: <strong>einen Bereich auswählen und eine Notiz hinzufügen</strong>, einen Kommentar hinterlassen oder per <strong>Inline-Bearbeitung</strong> Text direkt ändern. Wechsle in die <strong>Code</strong>-Ansicht, um das generierte HTML und die Designdateien zu sehen. Wenn du zufrieden bist, exportiert die Schaltfläche <strong>Teilen</strong> als PDF oder deployt direkt zu <strong>Vercel oder Cloudflare Pages</strong> (gib deinen Token ein, und die Seite geht live), oder du klickst zum Quellcode durch und arbeitest in VS Code, Cursor oder deinem Editor weiter.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Ein echter, in Open Design generierter Prototyp.\">\n<em>Ein echter generierter Prototyp in der Vorschau – eine dunkle, cineastische Agentur-Landingpage.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">Schritt 3 – Über Seiten hinaus: ein Video erzeugen</h2>\n<p>Open Design ist nicht auf statisches Design beschränkt. Roy nutzt die <strong>hyperframes</strong>-Motion-Skill, um ein animiertes Balkendiagramm im Stil der New York Times zu erzeugen – das dauert ein paar Minuten und produziert ein echtes MP4, das du in ein längeres Video einfügen oder als gebrandeten Schnipsel verwenden kannst. Es gibt außerdem über 170 Designsystem-Plugins zur Auswahl (Apple, PlayStation und mehr), und weil die Bibliothek offen ist, ergänzt die Community sie laufend.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Wann was nutzen (die ehrliche Einschätzung)</h2>\n<p>Roy bleibt dabei fair. Greif zu <strong>Open Design</strong>, wenn du Modellflexibilität, niedrigere Kosten oder Selbst-Hosting willst – die Arbeit bleibt auf deiner Maschine und läuft auf dem Modell deiner Wahl, einschließlich eines Drittanbieter-Modells. Greif zum <strong>geschlossenen Cloud-Tool</strong>, wenn du ein minimales Setup ohne Installation und den geringsten Aufwand zum Einstieg willst – und beachte, dass es ab Werk noch etwas geschliffener ist. Gleicher Inhalt, dort eine etwas höhere Politur; hier deutlich mehr Kontrolle und niedrigere Betriebskosten.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Lass es über den Agenten laufen, für den du ohnehin schon zahlst</strong> (oder BYOK), um einer separaten Token-Obergrenze zu entkommen.</li>\n<li><strong>Entwirf auf einem günstigen Modell, finalisiere auf einem starken</strong> – du steuerst den Kosten-Qualitäts-Regler pro Projekt.</li>\n<li><strong>Nutze Inline-Bearbeitung und Bereichskommentare</strong> für günstige, chirurgische Änderungen statt kompletter Neugenerierungen.</li>\n<li><strong>Exportiere zu Code oder deploye zu Vercel/Cloudflare</strong> direkt aus „Teilen“, wenn du fertig bist.</li>\n<li><strong>Probier die hyperframes-Skill</strong>, wenn du Bewegung/Video brauchst, nicht nur statische Seiten.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Wie spart das im Vergleich zu einem geschlossenen Cloud-Tool Tokens?</strong>\nDie Generierung läuft über deinen eigenen Agenten/dein Abo oder deinen eigenen API-Key, also gibt es kein separates getaktetes Design-Budget, das man aufbrauchen müsste – du wählst das Modell und die Kosten.</p>\n<p><strong>Kann ich an der Ausgabe in meinem Editor weiterarbeiten?</strong>\nJa – die Ausgabe ist editierbares HTML/Dateien. Klick zum Quellcode durch und mach in VS Code, Cursor oder einem beliebigen Editor weiter, oder deploye zu Vercel/Cloudflare Pages.</p>\n<p><strong>Kann es mehr als Webseiten?</strong>\nJa – Prototypen, Decks, Bilder und Video (über die hyperframes-Motion-Skill), plus eine große Bibliothek von Designsystemen.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist unter Apache-2.0 quelloffen und lokal kostenlos zu betreiben. Du zahlst nur für die Modell- und Mediennutzung des jeweiligen Agenten und Keys, die du verbindest.</p>\n<hr>\n<p><em>Dieser schriftliche Leitfaden basiert auf dem Walkthrough von Roy Shavit. Sieh dir oben das vollständige Video an und <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">abonniere Roy Shavit</a> für mehr praxisnahe AI-Build-Inhalte.</em></p>",
  },
  "fr": {
    title: "Concevoir avec une qualité digne de Claude Design sans brûler de tokens",
    summary: "Un guide d’Open Design centré sur le coût — échappez au plafond de tokens en faisant tourner la conception via l’agent que vous payez déjà (ou votre propre clé), construisez une landing page complète, générez même une vidéo, et déployez. Avec, en prime, un avis honnête sur « quand utiliser quel outil ». D’après la démonstration de Roy Shavit.",
    bodyHtml: "<p>Ce guide prend l’angle du coût de front : si vous avez utilisé un outil de design cloud fermé, vous connaissez la magie — et vous savez que les tokens s’épuisent vite. Open Design vous permet de concevoir avec une qualité comparable en faisant tourner le travail via <strong>n’importe quel modèle de votre choix</strong> — l’agent que vous payez déjà, ou votre propre clé — pour ne pas rationner un budget de design séparé. Il suit la construction que <strong>Roy Shavit</strong> réalise dans <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">sa démonstration</a>, réécrite en anglais et mise à jour avec la version actuelle. Regardez la vidéo ci-dessus pour la démonstration en direct, ou lisez la suite pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"La galerie de motion et de vidéo HyperFrames dans Open Design.\">\n<em>La galerie HyperFrames : des créations de motion et de vidéo pilotées par le code, à forker et à remixer.</em></p>\n<h2 id=\"what-is-open-design\">Qu’est-ce qu’Open Design ?</h2>\n<p>Open Design est une plateforme de design open source et local-first. Comme l’outil cloud fermé, vous lui donnez un prompt et récupérez un artefact réel — une landing page, une application ou un deck — sous forme de HTML modifiable sur lequel vous pouvez continuer à travailler dans VS Code ou votre éditeur. Trois choses le distinguent, et les deux premières expliquent pourquoi il revient moins cher :</p>\n<ul>\n<li><strong>Il est open source (Apache-2.0)</strong> — lisez le code, forkez-le, hébergez-le vous-même.</li>\n<li><strong>Il tourne sur votre ordinateur</strong> — les fichiers restent sur votre machine ; rien ne part vers un cloud tiers.</li>\n<li><strong>Il utilise n’importe quel modèle de votre choix</strong> — Codex, Claude, ou plus de 15 autres modèles via votre CLI existante, ou votre propre clé API (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">La question du coût : arrêtez de rationner les tokens</h2>\n<p>La formule de Roy est sans détour, et c’est tout l’enjeu : un outil de design cloud fermé épuise très vite son allocation de tokens, si bien que vous finissez par rationner votre travail de design. Open Design supprime ce plafond parce que <strong>la génération passe par l’agent/l’abonnement que vous avez déjà, ou une clé que vous contrôlez.</strong> Vous décidez du compromis coût/qualité projet par projet — un modèle bon marché pour les brouillons, un modèle haut de gamme pour la passe finale — au lieu d’être facturé au compteur par le plafond de design séparé d’un tiers. L’auto-hébergement signifie aussi que le travail se fait sur votre machine, ce qui garde tout léger.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">Étape 1 — Installer et détecter vos modèles</h2>\n<p>Le chemin le plus simple est l’<strong>application de bureau</strong> : rendez-vous sur <a href=\"https://open-design.ai/download\">open-design.ai/download</a>, choisissez votre OS, téléchargez et glissez-la dedans. Vous préférez les sources :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ouvrez l’URL locale qu’il affiche (un port dynamique — n’en codez aucun en dur). Dans les paramètres, Open Design <strong>reconnaît immédiatement les modèles installés localement</strong> — Roy a Codex et Claude, et il détecterait aussi OpenCode ou d’autres. Définissez un modèle par défaut, ou apportez votre propre clé de n’importe quel fournisseur, pour ne même pas avoir besoin d’une CLI installée. C’est là sa singularité : vous n’êtes pas forcé chez un seul fournisseur.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"Le mode présentation d'Open Design avec des exemples de decks.\">\n<em>Mode présentation : choisissez une catégorie de deck et forkez un exemple comme point de départ.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">Étape 2 — Construire une landing page, itérer à moindre coût</h2>\n<p>Roy construit une landing page pour un service de streaming de jeux. Il envoie le brief, Open Design renvoie un <strong>formulaire de découverte</strong> (type de sortie, audience, direction de marque, périmètre, niveau de mouvement), il répond, et il construit — en tournant ici sur Claude Opus parce que c’est ce que sa CLI a configuré. Le résultat est une solide première version : hero, chiffres de démo, prise en charge des plateformes, une page de tarifs, des témoignages, une FAQ — responsive sur ordinateur, tablette et téléphone.</p>\n<p>Les outils d’itération maintiennent le coût des changements bas : <strong>sélectionner une zone et ajouter une note</strong>, laisser un commentaire, ou faire de l’<strong>édition en ligne</strong> pour modifier le texte directement. Basculez en vue <strong>code</strong> pour voir le HTML généré et les fichiers de design. Quand vous êtes satisfait, le bouton <strong>Partager</strong> exporte en PDF ou déploie directement vers <strong>Vercel ou Cloudflare Pages</strong> (collez votre token et le site passe en ligne), ou vous cliquez vers la source et continuez dans VS Code, Cursor ou votre éditeur.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Un véritable prototype généré dans Open Design.\">\n<em>Un véritable prototype généré, rendu dans l'aperçu — une landing page d'agence sombre et cinématographique.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">Étape 3 — Au-delà des pages : générer une vidéo</h2>\n<p>Open Design ne se limite pas au design statique. Roy utilise la compétence de mouvement <strong>hyperframes</strong> pour générer un graphique à barres animé dans un style New York Times — cela prend quelques minutes et produit un vrai MP4 que vous pouvez intégrer dans une vidéo plus longue ou utiliser comme extrait de marque. Il y a aussi plus de 170 plugins de systèmes de design à choisir (Apple, PlayStation, et plus), et comme la bibliothèque est ouverte, la communauté continue d’y ajouter.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Quand utiliser quoi (l’avis honnête)</h2>\n<p>Roy est juste à ce sujet. Tournez-vous vers <strong>Open Design</strong> quand vous voulez de la flexibilité sur les modèles, un coût plus bas, ou l’auto-hébergement — le travail reste sur votre machine et tourne sur le modèle de votre choix, y compris un modèle tiers. Tournez-vous vers l’<strong>outil cloud fermé</strong> quand vous voulez une configuration minimale, sans installation, et le moins d’effort pour démarrer — et notez qu’il reste un peu plus abouti dès la sortie de boîte. Même contenu, finition légèrement supérieure là-bas ; nettement plus de contrôle et un coût de fonctionnement plus bas ici.</p>\n<h2 id=\"tips\">Conseils</h2>\n<ul>\n<li><strong>Faites tourner sur l’agent que vous payez déjà</strong> (ou BYOK) pour échapper à un plafond de tokens séparé.</li>\n<li><strong>Brouillonnez sur un modèle bon marché, finalisez sur un modèle puissant</strong> — vous contrôlez le curseur coût/qualité projet par projet.</li>\n<li><strong>Utilisez l’édition en ligne et les commentaires de zone</strong> pour des changements peu coûteux et chirurgicaux plutôt que des régénérations complètes.</li>\n<li><strong>Exportez vers le code ou déployez sur Vercel/Cloudflare</strong> directement depuis Partager une fois terminé.</li>\n<li><strong>Essayez la compétence hyperframes</strong> quand vous avez besoin de mouvement/vidéo, pas seulement de pages statiques.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>En quoi cela économise-t-il des tokens par rapport à un outil cloud fermé ?</strong>\nLa génération passe par votre propre agent/abonnement ou votre propre clé API, il n’y a donc pas de budget de design séparé compté au compteur à épuiser — vous choisissez le modèle et le coût.</p>\n<p><strong>Puis-je continuer à travailler la sortie dans mon éditeur ?</strong>\nOui — la sortie est du HTML/des fichiers modifiables. Cliquez vers la source et continuez dans VS Code, Cursor ou n’importe quel éditeur, ou déployez sur Vercel/Cloudflare Pages.</p>\n<p><strong>Peut-il faire plus que des pages web ?</strong>\nOui — prototypes, decks, images et vidéo (via la compétence de mouvement hyperframes), plus une grande bibliothèque de systèmes de design.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL’application est open source sous Apache-2.0 et gratuite à exécuter localement. Vous ne payez que l’usage du modèle et des médias de l’agent et de la clé que vous connectez.</p>\n<hr>\n<p><em>Ce guide écrit est basé sur la démonstration de Roy Shavit. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">abonnez-vous à Roy Shavit</a> pour plus de contenu pratique sur la création avec l’IA.</em></p>",
  },
  "ru": {
    title: "Дизайн с качеством на уровне Claude Design без сжигания токенов",
    summary: "Руководство по Open Design с упором на стоимость — вырвитесь из лимита токенов, прогоняя дизайн через агента, за которого вы уже платите (или через собственный ключ), соберите полноценный лендинг, даже сгенерируйте видео и задеплойте. Плюс честный разбор «когда какой инструмент использовать». По мотивам разбора Роя Шавита.",
    bodyHtml: "<p>Это руководство берёт вопрос стоимости в лоб: если вы пользовались закрытым облачным инструментом для дизайна, вы знаете магию — и знаете, как быстро кончаются токены. Open Design позволяет проектировать с похожим качеством, прогоняя работу через <strong>любую модель, какую захотите</strong> — агента, за которого вы уже платите, или ваш собственный ключ — так что вам не приходится экономить отдельный дизайн-бюджет. Он следует сборке, которую <strong>Рой Шавит</strong> проводит в <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">своём разборе</a>, переписанной на английском и обновлённой под текущий релиз. Смотрите видео выше для живого прохода или читайте дальше письменную версию.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"Галерея анимации и видео HyperFrames в Open Design.\">\n<em>Галерея HyperFrames: анимационные и видеоработы на основе кода, которые можно форкнуть и переработать.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это открытая, локальная в первую очередь платформа для дизайна. Как и у закрытого облачного инструмента, вы даёте ей промпт и получаете обратно настоящий артефакт — лендинг, приложение или дек — в виде редактируемого HTML, с которым можно продолжить работу в VS Code или вашем редакторе. Её выделяют три вещи, и первые две — причина, по которой её дешевле эксплуатировать:</p>\n<ul>\n<li><strong>Она с открытым исходным кодом (Apache-2.0)</strong> — читайте код, форкайте его, размещайте у себя.</li>\n<li><strong>Она работает на вашем компьютере</strong> — файлы остаются на вашей машине; ничто не уходит в стороннее облако.</li>\n<li><strong>Она использует любую модель, какую захотите</strong> — Codex, Claude или 15+ других моделей через ваш существующий CLI, либо ваш собственный ключ API (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">История о стоимости: перестаньте экономить токены</h2>\n<p>Формулировка Роя прямая, и в этом вся суть: закрытый облачный инструмент для дизайна очень быстро прожигает свой лимит токенов, так что вы в итоге экономите на дизайне. Open Design убирает этот потолок, потому что <strong>генерация идёт через агента/подписку, которые у вас уже есть, или через ключ, который вы контролируете.</strong> Вы сами решаете компромисс «стоимость/качество» для каждого проекта — дешёвая модель для черновиков, топовая модель для финального прохода — вместо того чтобы вас тарифицировал чей-то отдельный дизайн-лимит. Самостоятельный хостинг также означает, что работа происходит на вашей машине, что держит всё компактным.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">Шаг 1 — Установите и обнаружьте свои модели</h2>\n<p>Самый простой путь — <strong>десктопное приложение</strong>: зайдите на <a href=\"https://open-design.ai/download\">open-design.ai/download</a>, выберите свою ОС, скачайте и перетащите внутрь. Предпочитаете из исходников:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Откройте локальный URL, который он выводит (динамический порт — не прописывайте его жёстко). В настройках Open Design <strong>сразу распознаёт модели, установленные локально</strong> — у Роя есть Codex и Claude, и он подхватил бы OpenCode или другие. Задайте модель по умолчанию или подключите собственный ключ от любого провайдера, чтобы вам даже не понадобилось устанавливать CLI. В этом и уникальность: вас не загоняют к одному вендору.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"Режим слайд-презентаций в Open Design с примерами презентаций.\">\n<em>Режим слайд-презентаций: выберите категорию презентаций и форкните пример в качестве отправной точки.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">Шаг 2 — Соберите лендинг, итерируйте дёшево</h2>\n<p>Рой собирает лендинг для сервиса стриминга игр. Он отправляет бриф, Open Design возвращает <strong>форму уточнения</strong> (тип результата, аудитория, направление бренда, объём, уровень анимации), он отвечает, и тот собирает — здесь работает на Claude Opus, потому что так настроен его CLI. Результат — крепкая первая версия: герой, демо-цифры, поддержка платформ, страница тарифов, отзывы, FAQ — адаптивно на десктопе, планшете и телефоне.</p>\n<p>Инструменты итерации держат стоимость изменений низкой: <strong>выделите область и добавьте заметку</strong>, оставьте комментарий или сделайте <strong>встроенное редактирование</strong>, чтобы изменить текст напрямую. Переключитесь в режим <strong>кода</strong>, чтобы увидеть сгенерированный HTML и файлы дизайна. Когда довольны, кнопка <strong>Поделиться</strong> экспортирует в PDF или деплоит прямо на <strong>Vercel или Cloudflare Pages</strong> (вставьте свой токен — и сайт уйдёт в онлайн), либо вы переходите к исходникам и продолжаете в VS Code, Cursor или вашем редакторе.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Реальный прототип, сгенерированный в Open Design.\">\n<em>Реальный сгенерированный прототип в предпросмотре — тёмная, кинематографичная лендинг-страница агентства.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">Шаг 3 — За пределами страниц: сгенерируйте видео</h2>\n<p>Open Design не ограничивается статичным дизайном. Рой использует навык анимации <strong>hyperframes</strong>, чтобы сгенерировать анимированную столбчатую диаграмму в стиле New York Times — это занимает несколько минут и даёт настоящий MP4, который можно вставить в более длинное видео или использовать как брендированный фрагмент. Есть также более 170 плагинов дизайн-систем на выбор (Apple, PlayStation и другие), и поскольку библиотека открытая, сообщество продолжает её пополнять.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Когда что использовать (честная оценка)</h2>\n<p>Рой честен на этот счёт. Тянитесь к <strong>Open Design</strong>, когда вам нужна гибкость по моделям, более низкая стоимость или самостоятельный хостинг — работа остаётся на вашей машине и идёт на любой выбранной вами модели, в том числе сторонней. Тянитесь к <strong>закрытому облачному инструменту</strong>, когда вам нужна минимальная установка без инсталляции и наименьшие усилия для старта — и учтите, что «из коробки» он по-прежнему чуть более отполирован. Тот же контент, там немного выше отделка; здесь — заметно больше контроля и более низкая стоимость эксплуатации.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Запускайте на агенте, за которого вы уже платите</strong> (или BYOK), чтобы вырваться из отдельного лимита токенов.</li>\n<li><strong>Черновики на дешёвой модели, финал на сильной</strong> — вы управляете рычагом «стоимость/качество» для каждого проекта.</li>\n<li><strong>Используйте встроенное редактирование и комментарии к областям</strong> для дешёвых точечных изменений вместо полной перегенерации.</li>\n<li><strong>Экспортируйте в код или деплойте на Vercel/Cloudflare</strong> прямо из «Поделиться», когда закончите.</li>\n<li><strong>Попробуйте навык hyperframes</strong>, когда нужны анимация/видео, а не только статичные страницы.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Как это экономит токены по сравнению с закрытым облачным инструментом?</strong>\nГенерация идёт через вашего собственного агента/подписку или ваш собственный ключ API, поэтому нет отдельного тарифицируемого дизайн-бюджета, который нужно исчерпать — вы выбираете модель и стоимость.</p>\n<p><strong>Могу ли я продолжить работать с результатом в своём редакторе?</strong>\nДа — результат это редактируемый HTML/файлы. Перейдите к исходникам и продолжите в VS Code, Cursor или любом редакторе, либо задеплойте на Vercel/Cloudflare Pages.</p>\n<p><strong>Может ли он делать больше, чем веб-страницы?</strong>\nДа — прототипы, деки, изображения и видео (через навык анимации hyperframes), плюс большую библиотеку дизайн-систем.</p>\n<p><strong>Это бесплатно?</strong>\nПриложение с открытым исходным кодом под Apache-2.0 и бесплатно для локального запуска. Вы платите только за использование модели и медиа того агента и ключа, которые подключаете.</p>\n<hr>\n<p><em>Это письменное руководство основано на разборе Роя Шавита. Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">подпишитесь на Роя Шавита</a>, чтобы получать больше практического контента о сборке с ИИ.</em></p>",
  },
  "es": {
    title: "Diseña con la calidad de Claude Design sin quemar tokens",
    summary: "Una guía de Open Design centrada en el costo: escapa del tope de tokens ejecutando el diseño a través del agente que ya pagas (o tu propia clave), construye una landing page completa, incluso genera un video y despliega. Además, una valoración honesta de «cuándo usar cada herramienta». Basada en el recorrido de Roy Shavit.",
    bodyHtml: "<p>Esta guía aborda el ángulo del costo de frente: si has usado una herramienta de diseño en la nube cerrada, conoces la magia, y sabes que los tokens se agotan rápido. Open Design te permite diseñar con una calidad similar ejecutando el trabajo a través de <strong>cualquier modelo que quieras</strong>: el agente que ya pagas, o tu propia clave, de modo que no tengas que racionar un presupuesto de diseño aparte. Sigue la construcción que <strong>Roy Shavit</strong> realiza en <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">su recorrido</a>, reescrita en inglés y puesta al día con la versión actual. Mira el video de arriba para verlo en vivo, o sigue leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"La galería de motion y vídeo HyperFrames en Open Design.\">\n<em>La galería HyperFrames: piezas de motion y vídeo impulsadas por código que puedes forkear y remezclar.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño de código abierto y local-first. Como la herramienta en la nube cerrada, le das un prompt y te devuelve un artefacto real —una landing page, una app o un deck— como HTML editable con el que puedes seguir trabajando en VS Code o tu editor. Tres cosas lo distinguen, y las dos primeras son la razón de que sea más barato de operar:</p>\n<ul>\n<li><strong>Es de código abierto (Apache-2.0)</strong>: lee el código, haz un fork, hospédalo tú mismo.</li>\n<li><strong>Se ejecuta en tu computadora</strong>: los archivos se quedan en tu máquina; nada va a una nube de terceros.</li>\n<li><strong>Usa cualquier modelo que quieras</strong>: Codex, Claude o más de 15 modelos más a través de tu CLI existente, o tu propia clave de API (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">La cuestión del costo: deja de racionar tokens</h2>\n<p>El planteamiento de Roy es directo y es justo el punto: una herramienta de diseño en la nube cerrada agota su asignación de tokens muy rápido, así que terminas racionando tu trabajo de diseño. Open Design elimina ese techo porque <strong>la generación corre a través del agente/suscripción que ya tienes, o una clave que controlas.</strong> Tú decides el compromiso costo/calidad por proyecto —un modelo barato para borradores, un modelo de primer nivel para la pasada final— en lugar de que te mida un tope de diseño aparte de otra persona. El autohospedaje también significa que el trabajo ocurre en tu máquina, lo que mantiene todo ligero.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">Paso 1: Instala y detecta tus modelos</h2>\n<p>El camino más simple es la <strong>app de escritorio</strong>: ve a <a href=\"https://open-design.ai/download\">open-design.ai/download</a>, elige tu sistema operativo, descárgala y arrástrala. ¿Prefieres el código fuente?:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre la URL local que imprime (un puerto dinámico: no lo fijes a mano). En la configuración, Open Design <strong>reconoce de inmediato los modelos instalados localmente</strong>: Roy tiene Codex y Claude, y también detectaría OpenCode u otros. Establece uno por defecto, o trae tu propia clave de cualquier proveedor para no necesitar siquiera una CLI instalada. Esa es la singularidad: no te obligan a un único proveedor.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"El modo de presentación de diapositivas en Open Design con ejemplos de presentaciones.\">\n<em>Modo de presentación: elige una categoría de presentación y haz un fork de un ejemplo como punto de partida.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">Paso 2: Construye una landing page, itera barato</h2>\n<p>Roy construye una landing page para un servicio de streaming de juegos. Envía el brief, Open Design devuelve un <strong>formulario de descubrimiento</strong> (tipo de salida, audiencia, dirección de marca, alcance, nivel de movimiento), él responde y la construye, ejecutándose aquí en Claude Opus porque es lo que tiene configurado su CLI. El resultado es una primera versión sólida: hero, cifras de demo, soporte de plataformas, una página de precios, testimonios, FAQ, responsive en escritorio, tablet y teléfono.</p>\n<p>Las herramientas de iteración mantienen bajo el costo de los cambios: <strong>selecciona un área y añade una nota</strong>, deja un comentario o haz <strong>edición en línea</strong> para cambiar el texto directamente. Cambia a la vista de <strong>código</strong> para ver el HTML generado y los archivos de diseño. Cuando estés satisfecho, el botón <strong>Compartir</strong> exporta a PDF o despliega directo a <strong>Vercel o Cloudflare Pages</strong> (pega tu token y el sitio queda en vivo), o haces clic hacia el código y sigues trabajando en VS Code, Cursor o tu editor.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Un prototipo real generado en Open Design.\">\n<em>Un prototipo real generado, renderizado en la vista previa: una landing page de agencia oscura y cinematográfica.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">Paso 3: Más allá de las páginas: genera un video</h2>\n<p>Open Design no se limita al diseño estático. Roy usa la habilidad de movimiento <strong>hyperframes</strong> para generar un gráfico de barras animado al estilo del New York Times: tarda unos minutos y produce un MP4 real que puedes insertar en un video más largo o usar como un fragmento de marca. También hay más de 170 plugins de sistemas de diseño para elegir (Apple, PlayStation y más), y como la biblioteca es abierta, la comunidad sigue ampliándola.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Cuándo usar cada uno (la valoración honesta)</h2>\n<p>Roy es justo al respecto. Recurre a <strong>Open Design</strong> cuando quieras flexibilidad de modelos, menor costo o autohospedaje: el trabajo se queda en tu máquina y corre en el modelo que elijas, incluido uno de terceros. Recurre a la <strong>herramienta en la nube cerrada</strong> cuando quieras una configuración mínima, sin instalación, y el menor esfuerzo para empezar; y ten en cuenta que de fábrica todavía está un poco más pulida. Mismo contenido, un acabado ligeramente mayor allá; bastante más control y menor costo de operación aquí.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Ejecuta en el agente que ya pagas</strong> (o BYOK) para escapar de un tope de tokens aparte.</li>\n<li><strong>Haz el borrador en un modelo barato, termina en uno potente</strong>: tú controlas el dial de costo/calidad por proyecto.</li>\n<li><strong>Usa la edición en línea y los comentarios por área</strong> para cambios baratos y quirúrgicos en lugar de regeneraciones completas.</li>\n<li><strong>Exporta a código o despliega en Vercel/Cloudflare</strong> directo desde Compartir cuando termines.</li>\n<li><strong>Prueba la habilidad hyperframes</strong> cuando necesites movimiento/video, no solo páginas estáticas.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿Cómo ahorra tokens esto frente a una herramienta en la nube cerrada?</strong>\nLa generación corre a través de tu propio agente/suscripción o tu propia clave de API, así que no hay un presupuesto de diseño aparte medido que agotar: tú eliges el modelo y el costo.</p>\n<p><strong>¿Puedo seguir trabajando la salida en mi editor?</strong>\nSí: la salida es HTML/archivos editables. Haz clic hacia el código y continúa en VS Code, Cursor o cualquier editor, o despliega en Vercel/Cloudflare Pages.</p>\n<p><strong>¿Puede hacer algo más que páginas web?</strong>\nSí: prototipos, decks, imágenes y video (mediante la habilidad de movimiento hyperframes), además de una gran biblioteca de sistemas de diseño.</p>\n<p><strong>¿Es gratis?</strong>\nLa app es de código abierto bajo Apache-2.0 y gratuita para ejecutar en local. Solo pagas por el uso de modelo y medios del agente y la clave que conectes.</p>\n<hr>\n<p><em>Esta guía escrita se basa en el recorrido de Roy Shavit. Mira el video completo arriba y <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">suscríbete a Roy Shavit</a> para más contenido práctico de construcción con IA.</em></p>",
  },
  "pt-br": {
    title: "Crie com a qualidade do Claude Design sem queimar tokens",
    summary: "Um guia do Open Design com foco no custo — escape do teto de tokens rodando o design pelo agente que você já paga (ou pela sua própria chave), construa uma landing page completa, gere até um vídeo e faça o deploy. Além de uma avaliação honesta de \"quando usar cada ferramenta\". Baseado na demonstração de Roy Shavit.",
    bodyHtml: "<p>Este guia encara o ângulo do custo de frente: se você já usou uma ferramenta de design em nuvem fechada, conhece a mágica — e sabe que os tokens acabam rápido. O Open Design permite que você projete com qualidade semelhante rodando o trabalho por <strong>qualquer modelo que você quiser</strong> — o agente que você já paga, ou a sua própria chave — para não ter que racionar um orçamento de design separado. Ele segue a construção que <strong>Roy Shavit</strong> faz em <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">sua demonstração</a>, reescrita em inglês e atualizada para a versão atual. Assista ao vídeo acima para ver ao vivo, ou continue lendo a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"A galeria de motion e vídeo HyperFrames no Open Design.\">\n<em>A galeria HyperFrames: peças de motion e vídeo orientadas por código que você pode forkar e remixar.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design de código aberto e local-first. Como a ferramenta em nuvem fechada, você dá um prompt e recebe de volta um artefato real — uma landing page, app ou deck — como HTML editável no qual você pode continuar trabalhando no VS Code ou no seu editor. Três coisas o diferenciam, e as duas primeiras são o motivo de ser mais barato de operar:</p>\n<ul>\n<li><strong>É de código aberto (Apache-2.0)</strong> — leia o código, faça um fork, hospede você mesmo.</li>\n<li><strong>Roda no seu computador</strong> — os arquivos ficam na sua máquina; nada vai para uma nuvem de terceiros.</li>\n<li><strong>Usa qualquer modelo que você quiser</strong> — Codex, Claude ou mais de 15 outros modelos via sua CLI existente, ou sua própria chave de API (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">A questão do custo: pare de racionar tokens</h2>\n<p>A formulação de Roy é direta e é exatamente o ponto: uma ferramenta de design em nuvem fechada consome sua cota de tokens muito rápido, então você acaba racionando o seu trabalho de design. O Open Design remove esse teto porque <strong>a geração roda pelo agente/assinatura que você já tem, ou por uma chave que você controla.</strong> Você decide o equilíbrio custo/qualidade por projeto — um modelo barato para rascunhos, um modelo de ponta para a passada final — em vez de ser tarifado pelo teto de design separado de outra pessoa. A auto-hospedagem também significa que o trabalho acontece na sua máquina, o que mantém tudo enxuto.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">Passo 1 — Instale e detecte seus modelos</h2>\n<p>O caminho mais simples é o <strong>app de desktop</strong>: vá em <a href=\"https://open-design.ai/download\">open-design.ai/download</a>, escolha seu sistema operacional, baixe e arraste para dentro. Prefere o código-fonte:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abra a URL local que ele imprime (uma porta dinâmica — não fixe nenhuma no código). Nas configurações, o Open Design <strong>reconhece imediatamente os modelos instalados localmente</strong> — Roy tem Codex e Claude, e ele também captaria o OpenCode ou outros. Defina um padrão, ou traga sua própria chave de qualquer provedor para nem precisar de uma CLI instalada. Essa é a singularidade: você não é forçado a um único fornecedor.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"O modo de apresentação de slides no Open Design com exemplos de apresentações.\">\n<em>Modo de apresentação de slides: escolha uma categoria de apresentação e faça um fork de um exemplo como ponto de partida.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">Passo 2 — Construa uma landing page, itere barato</h2>\n<p>Roy constrói uma landing page para um serviço de streaming de jogos. Ele envia o briefing, o Open Design retorna um <strong>formulário de descoberta</strong> (tipo de saída, público, direção de marca, escopo, nível de movimento), ele responde, e ele constrói — rodando aqui no Claude Opus porque é o que sua CLI está configurada para usar. O resultado é uma primeira versão sólida: hero, números de demo, suporte a plataformas, uma página de preços, depoimentos, FAQ — responsiva em desktop, tablet e celular.</p>\n<p>As ferramentas de iteração mantêm baixo o custo das mudanças: <strong>selecione uma área e adicione uma nota</strong>, deixe um comentário ou faça <strong>edição inline</strong> para alterar o texto diretamente. Mude para a visão de <strong>código</strong> para ver o HTML gerado e os arquivos de design. Quando estiver satisfeito, o botão <strong>Compartilhar</strong> exporta para PDF ou faz deploy direto para o <strong>Vercel ou Cloudflare Pages</strong> (cole seu token e o site vai ao ar), ou você clica para o código-fonte e continua trabalhando no VS Code, Cursor ou no seu editor.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Um protótipo real gerado no Open Design.\">\n<em>Um protótipo real gerado, renderizado na pré-visualização — uma landing page de agência escura e cinematográfica.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">Passo 3 — Além das páginas: gere um vídeo</h2>\n<p>O Open Design não se limita a design estático. Roy usa a skill de movimento <strong>hyperframes</strong> para gerar um gráfico de barras animado no estilo do New York Times — leva alguns minutos e produz um MP4 de verdade que você pode inserir em um vídeo mais longo ou usar como um trecho de marca. Há também mais de 170 plugins de design systems para escolher (Apple, PlayStation e mais), e como a biblioteca é aberta, a comunidade continua acrescentando a ela.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Quando usar qual (a avaliação honesta)</h2>\n<p>Roy é justo quanto a isso. Recorra ao <strong>Open Design</strong> quando quiser flexibilidade de modelos, custo menor ou auto-hospedagem — o trabalho fica na sua máquina e roda no modelo que você escolher, inclusive um de terceiros. Recorra à <strong>ferramenta em nuvem fechada</strong> quando quiser uma configuração mínima, sem instalação, e o menor esforço para começar — e note que ela ainda é um pouco mais polida de cara. Mesmo conteúdo, um acabamento ligeiramente maior lá; bem mais controle e custo de operação menor aqui.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Rode no agente que você já paga</strong> (ou BYOK) para escapar de um teto de tokens separado.</li>\n<li><strong>Rascunhe em um modelo barato, finalize em um forte</strong> — você controla o botão de custo/qualidade por projeto.</li>\n<li><strong>Use edição inline e comentários por área</strong> para mudanças baratas e cirúrgicas em vez de regenerações completas.</li>\n<li><strong>Exporte para código ou faça deploy no Vercel/Cloudflare</strong> direto pelo Compartilhar quando terminar.</li>\n<li><strong>Experimente a skill hyperframes</strong> quando precisar de movimento/vídeo, não apenas páginas estáticas.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Como isso economiza tokens em comparação com uma ferramenta em nuvem fechada?</strong>\nA geração roda pelo seu próprio agente/assinatura ou pela sua própria chave de API, então não há um orçamento de design separado e tarifado para esgotar — você escolhe o modelo e o custo.</p>\n<p><strong>Posso continuar trabalhando a saída no meu editor?</strong>\nSim — a saída é HTML/arquivos editáveis. Clique para o código-fonte e continue no VS Code, Cursor ou em qualquer editor, ou faça deploy no Vercel/Cloudflare Pages.</p>\n<p><strong>Ele faz mais do que páginas web?</strong>\nSim — protótipos, decks, imagens e vídeo (via a skill de movimento hyperframes), além de uma grande biblioteca de design systems.</p>\n<p><strong>É gratuito?</strong>\nO app é de código aberto sob Apache-2.0 e gratuito para rodar localmente. Você paga apenas pelo uso de modelo e mídia do agente e da chave que conectar.</p>\n<hr>\n<p><em>Este guia escrito é baseado na demonstração de Roy Shavit. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">inscreva-se no canal de Roy Shavit</a> para mais conteúdo prático de construção com IA.</em></p>",
  },
  "it": {
    title: "Progetta con la qualità di Claude Design senza bruciare token",
    summary: "Una guida a Open Design incentrata sul costo: sfuggi al tetto dei token facendo girare il design attraverso l’agente che già paghi (o la tua chiave), costruisci una landing page completa, genera persino un video e fai il deploy. In più, un giudizio onesto su «quando usare quale strumento». Basata sulla dimostrazione di Roy Shavit.",
    bodyHtml: "<p>Questa guida affronta il tema del costo di petto: se hai usato uno strumento di design cloud chiuso, conosci la magia, e sai quanto in fretta finiscono i token. Open Design ti permette di progettare con una qualità simile facendo girare il lavoro attraverso <strong>qualsiasi modello tu voglia</strong> — l’agente che già paghi, o la tua chiave — così non devi razionare un budget di design separato. Segue la costruzione che <strong>Roy Shavit</strong> esegue nella <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">sua dimostrazione</a>, riscritta in inglese e aggiornata alla versione attuale. Guarda il video qui sopra per la prova dal vivo, o continua a leggere per la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"La galleria di motion e video HyperFrames in Open Design.\">\n<em>La galleria HyperFrames: contenuti di motion e video guidati dal codice, da forkare e remixare.</em></p>\n<h2 id=\"what-is-open-design\">Che cos’è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first. Come lo strumento cloud chiuso, gli dai un prompt e ricevi un artefatto reale — una landing page, un’app o un deck — sotto forma di HTML modificabile su cui puoi continuare a lavorare in VS Code o nel tuo editor. Tre cose lo distinguono, e le prime due sono il motivo per cui costa meno gestirlo:</p>\n<ul>\n<li><strong>È open source (Apache-2.0)</strong> — leggi il codice, fanne un fork, ospitalo tu stesso.</li>\n<li><strong>Gira sul tuo computer</strong> — i file restano sulla tua macchina; nulla va su un cloud di terze parti.</li>\n<li><strong>Usa qualsiasi modello tu voglia</strong> — Codex, Claude o oltre 15 altri modelli tramite la tua CLI esistente, o la tua chiave API (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">La questione del costo: smetti di razionare i token</h2>\n<p>L’impostazione di Roy è schietta ed è proprio il punto: uno strumento di design cloud chiuso brucia la sua dotazione di token molto in fretta, così finisci per razionare il tuo lavoro di design. Open Design rimuove quel tetto perché <strong>la generazione gira attraverso l’agente/abbonamento che hai già, o una chiave che controlli tu.</strong> Decidi tu il compromesso costo/qualità per ogni progetto — un modello economico per le bozze, un modello di punta per la passata finale — invece di essere contabilizzato dal tetto di design separato di qualcun altro. Il self-hosting significa anche che il lavoro avviene sulla tua macchina, il che mantiene tutto leggero.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">Passo 1 — Installa e rileva i tuoi modelli</h2>\n<p>La via più semplice è l’<strong>app desktop</strong>: vai su <a href=\"https://open-design.ai/download\">open-design.ai/download</a>, scegli il tuo sistema operativo, scaricala e trascinala dentro. Preferisci i sorgenti:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Apri l’URL locale che stampa (una porta dinamica — non fissarne nessuna nel codice). Nelle impostazioni, Open Design <strong>riconosce immediatamente i modelli installati localmente</strong> — Roy ha Codex e Claude, e rileverebbe anche OpenCode o altri. Imposta un modello predefinito, o porta la tua chiave da qualsiasi provider così da non aver nemmeno bisogno di una CLI installata. È questa l’unicità: non sei costretto a un unico fornitore.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"La modalità presentazione in Open Design con esempi di presentazioni.\">\n<em>Modalità presentazione: scegli una categoria di presentazione e fai il fork di un esempio come punto di partenza.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">Passo 2 — Costruisci una landing page, itera a basso costo</h2>\n<p>Roy costruisce una landing page per un servizio di game streaming. Invia il brief, Open Design restituisce un <strong>modulo di scoperta</strong> (tipo di output, pubblico, direzione del brand, ambito, livello di movimento), lui risponde e lo costruisce — qui girando su Claude Opus perché è ciò che la sua CLI è impostata a usare. Il risultato è una solida prima versione: hero, numeri della demo, supporto alle piattaforme, una pagina prezzi, testimonianze, FAQ — responsive su desktop, tablet e telefono.</p>\n<p>Gli strumenti di iterazione mantengono basso il costo delle modifiche: <strong>seleziona un’area e aggiungi una nota</strong>, lascia un commento, o fai <strong>editing inline</strong> per cambiare il testo direttamente. Passa alla vista <strong>codice</strong> per vedere l’HTML generato e i file di design. Quando sei soddisfatto, il pulsante <strong>Condividi</strong> esporta in PDF o fa il deploy diretto su <strong>Vercel o Cloudflare Pages</strong> (incolla il tuo token e il sito va online), oppure clicchi verso il sorgente e continui a lavorare in VS Code, Cursor o nel tuo editor.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Un vero prototipo generato in Open Design.\">\n<em>Un vero prototipo generato, mostrato nell'anteprima: una landing page d'agenzia scura e cinematografica.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">Passo 3 — Oltre le pagine: genera un video</h2>\n<p>Open Design non si limita al design statico. Roy usa la skill di motion <strong>hyperframes</strong> per generare un grafico a barre animato in stile New York Times — ci vogliono pochi minuti e produce un vero MP4 che puoi inserire in un video più lungo o usare come spezzone brandizzato. Ci sono inoltre oltre 170 plugin di design system tra cui scegliere (Apple, PlayStation e altri), e poiché la libreria è aperta, la community continua ad ampliarla.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Quando usare cosa (il giudizio onesto)</h2>\n<p>Roy è equo su questo. Affidati a <strong>Open Design</strong> quando vuoi flessibilità di modelli, costi più bassi o self-hosting — il lavoro resta sulla tua macchina e gira sul modello che scegli, compreso uno di terze parti. Affidati allo <strong>strumento cloud chiuso</strong> quando vuoi una configurazione minima, senza installazione, e il minimo sforzo per iniziare — e tieni presente che è ancora un po’ più rifinito out of the box. Stesso contenuto, una finitura leggermente superiore là; qui molto più controllo e costi di gestione inferiori.</p>\n<h2 id=\"tips\">Consigli</h2>\n<ul>\n<li><strong>Fai girare sull’agente che già paghi</strong> (o BYOK) per sfuggire a un tetto di token separato.</li>\n<li><strong>Abbozza su un modello economico, rifinisci su uno potente</strong> — controlli tu la manopola costo/qualità per ogni progetto.</li>\n<li><strong>Usa l’editing inline e i commenti per area</strong> per modifiche economiche e chirurgiche invece di rigenerazioni complete.</li>\n<li><strong>Esporta in codice o fai il deploy su Vercel/Cloudflare</strong> direttamente da Condividi quando hai finito.</li>\n<li><strong>Prova la skill hyperframes</strong> quando ti serve movimento/video, non solo pagine statiche.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>In che modo questo fa risparmiare token rispetto a uno strumento cloud chiuso?</strong>\nLa generazione gira attraverso il tuo agente/abbonamento o la tua chiave API, quindi non c’è un budget di design separato contabilizzato da esaurire — scegli tu il modello e il costo.</p>\n<p><strong>Posso continuare a lavorare l’output nel mio editor?</strong>\nSì — l’output è HTML/file modificabili. Clicca verso il sorgente e continua in VS Code, Cursor o qualsiasi editor, oppure fai il deploy su Vercel/Cloudflare Pages.</p>\n<p><strong>Può fare più delle sole pagine web?</strong>\nSì — prototipi, deck, immagini e video (tramite la skill di motion hyperframes), oltre a una vasta libreria di design system.</p>\n<p><strong>È gratis?</strong>\nL’app è open source sotto Apache-2.0 e gratuita da eseguire localmente. Paghi solo per l’uso di modello e media dell’agente e della chiave che colleghi.</p>\n<hr>\n<p><em>Questa guida scritta è basata sulla dimostrazione di Roy Shavit. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">iscriviti a Roy Shavit</a> per altri contenuti pratici sulla costruzione con l’IA.</em></p>",
  },
  "tr": {
    title: "Token yakmadan Claude Design kalitesinde tasarım yapın",
    summary: "Open Design için maliyet odaklı bir rehber — zaten parasını ödediğiniz ajan (ya da kendi anahtarınız) üzerinden tasarımı çalıştırarak token tavanından kurtulun, eksiksiz bir açılış sayfası kurun, hatta bir video oluşturup yayına alın. Üstüne, \"hangi durumda hangi aracı kullanmalı\" konusunda dürüst bir değerlendirme. Roy Shavit'in adım adım anlatımına dayanır.",
    bodyHtml: "<p>Bu rehber maliyet meselesini doğrudan ele alır: kapalı bir bulut tasarım aracı kullandıysanız o sihri bilirsiniz — ve token'ların ne kadar çabuk tükendiğini de. Open Design, işi <strong>istediğiniz herhangi bir model</strong> üzerinden çalıştırarak benzer bir kalitede tasarım yapmanızı sağlar — zaten parasını ödediğiniz ajan ya da kendi anahtarınız — böylece ayrı bir tasarım bütçesini idareli kullanmak zorunda kalmazsınız. <strong>Roy Shavit</strong>'in <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">adım adım anlatımında</a> yaptığı kurulumu izler; İngilizceye yeniden yazılmış ve güncel sürüme uyarlanmıştır. Canlı çalıştırma için yukarıdaki videoyu izleyin ya da yazılı sürüm için okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/motion-gallery.webp\" alt=\"Open Design'daki HyperFrames hareket ve video galerisi.\">\n<em>HyperFrames galerisi: fork'layıp yeniden düzenleyebileceğiniz, kodla yönlendirilen hareket ve video çalışmaları.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, açık kaynaklı ve yerel öncelikli bir tasarım platformudur. Kapalı bulut aracında olduğu gibi, ona bir komut verir ve gerçek bir çıktı alırsınız — bir açılış sayfası, uygulama ya da deste — VS Code'da veya kendi düzenleyicinizde üzerinde çalışmaya devam edebileceğiniz düzenlenebilir HTML olarak. Onu öne çıkaran üç şey var ve ilk ikisi, çalıştırmasının neden daha ucuz olduğunu açıklıyor:</p>\n<ul>\n<li><strong>Açık kaynaklıdır (Apache-2.0)</strong> — kodu okuyun, fork'layın, kendiniz barındırın.</li>\n<li><strong>Sizin bilgisayarınızda çalışır</strong> — dosyalar makinenizde kalır; hiçbir şey üçüncü taraf bir buluta gitmez.</li>\n<li><strong>İstediğiniz herhangi bir modeli kullanır</strong> — mevcut CLI'niz üzerinden Codex, Claude ya da 15'ten fazla başka model, veya kendi API anahtarınız (BYOK).</li>\n</ul>\n<h2 id=\"the-cost-story-stop-rationing-tokens\">Maliyet meselesi: token'ları idareli kullanmayı bırakın</h2>\n<p>Roy'un çerçevesi açık sözlü ve mesele de tam olarak bu: kapalı bir bulut tasarım aracı token tahsisini çok hızlı tüketir, böylece sonunda tasarım işinizi idareli kullanmaya başlarsınız. Open Design bu tavanı kaldırır çünkü <strong>üretim, zaten sahip olduğunuz ajan/abonelik ya da kontrolünüzdeki bir anahtar üzerinden çalışır.</strong> Maliyet/kalite dengesine her proje için kendiniz karar verirsiniz — taslaklar için ucuz bir model, son geçiş için üst düzey bir model — başkasının ayrı tasarım tavanı tarafından sayaca bağlanmak yerine. Kendi sunucunuzda barındırmak ayrıca işin makinenizde gerçekleştiği anlamına gelir, bu da her şeyi yalın tutar.</p>\n<h2 id=\"step-1--install-and-detect-your-models\">1. Adım — Kurun ve modellerinizi algılayın</h2>\n<p>En basit yol <strong>masaüstü uygulamasıdır</strong>: <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresine gidin, işletim sisteminizi seçin, indirin ve sürükleyip bırakın. Kaynaktan kurmayı tercih ederseniz:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Yazdırdığı yerel URL'yi açın (dinamik bir port — hiçbirini sabit kodlamayın). Ayarlarda Open Design, <strong>yerel olarak kurulu modelleri anında tanır</strong> — Roy'da Codex ve Claude var ve OpenCode'u ya da başkalarını da yakalardı. Bir varsayılan belirleyin ya da herhangi bir sağlayıcıdan kendi anahtarınızı getirin; böylece kurulu bir CLI'ye bile ihtiyacınız olmaz. İşte benzersizliği bu: tek bir sağlayıcıya mahkûm edilmezsiniz.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/slide-deck-creator.webp\" alt=\"Open Design'da örnek sunumlarla birlikte slayt sunumu modu.\">\n<em>Slayt sunumu modu: bir sunum kategorisi seçin ve başlangıç noktası olarak bir örneği fork'layın.</em></p>\n<h2 id=\"step-2--build-a-landing-page-iterate-cheaply\">2. Adım — Bir açılış sayfası kurun, ucuza yineleyin</h2>\n<p>Roy bir oyun yayıncılığı hizmeti için bir açılış sayfası kuruyor. Brief'i gönderiyor, Open Design bir <strong>keşif formu</strong> (çıktı türü, hedef kitle, marka yönü, kapsam, hareket düzeyi) döndürüyor, o yanıtlıyor ve sayfayı kuruyor — CLI'si öyle ayarlı olduğu için burada Claude Opus üzerinde çalışıyor. Sonuç sağlam bir ilk sürüm: hero bölümü, demo rakamları, platform desteği, bir fiyatlandırma sayfası, kullanıcı görüşleri, SSS — masaüstü, tablet ve telefonda duyarlı.</p>\n<p>Yineleme araçları, değişikliklerin maliyetini düşük tutar: <strong>bir alanı seçip not ekleyin</strong>, bir yorum bırakın ya da metni doğrudan değiştirmek için <strong>satır içi düzenleme</strong> yapın. Üretilen HTML'i ve tasarım dosyalarını görmek için <strong>kod</strong> görünümüne geçin. Memnun kaldığınızda <strong>Paylaş</strong> düğmesi PDF'e aktarır ya da doğrudan <strong>Vercel veya Cloudflare Pages</strong>'e yayına alır (token'ınızı yapıştırın, site yayına girer), veya kaynağa tıklayıp VS Code, Cursor ya da kendi düzenleyicinizde çalışmaya devam edersiniz.</p>\n<p><img src=\"/tutorials/open-design-open-design-vs-claude-design-landing-page-roy-shavit/generated-prototype.webp\" alt=\"Open Design'da üretilen gerçek bir prototip.\">\n<em>Önizlemede gösterilen gerçek bir üretilmiş prototip — koyu, sinematik bir ajans açılış sayfası.</em></p>\n<h2 id=\"step-3--beyond-pages-generate-a-video\">3. Adım — Sayfaların ötesinde: bir video oluşturun</h2>\n<p>Open Design statik tasarımla sınırlı değildir. Roy, New York Times tarzında animasyonlu bir çubuk grafiği oluşturmak için <strong>hyperframes</strong> hareket becerisini kullanıyor — birkaç dakika sürüyor ve daha uzun bir videoya yerleştirebileceğiniz ya da markalı bir parça olarak kullanabileceğiniz gerçek bir MP4 üretiyor. Seçilebilecek 170'ten fazla tasarım sistemi eklentisi de var (Apple, PlayStation ve daha fazlası) ve kütüphane açık olduğundan topluluk ona eklemeye devam ediyor.</p>\n<h2 id=\"when-to-use-which-the-honest-call\">Hangisini ne zaman kullanmalı (dürüst değerlendirme)</h2>\n<p>Roy bu konuda adil. Model esnekliği, daha düşük maliyet ya da kendi sunucunuzda barındırma istediğinizde <strong>Open Design</strong>'a yönelin — iş makinenizde kalır ve üçüncü taraf bir model dâhil olmak üzere seçtiğiniz herhangi bir model üzerinde çalışır. Minimum, kurulum gerektirmeyen bir yapı ve başlamak için en az çabayı istediğinizde <strong>kapalı bulut aracına</strong> yönelin — ve kutudan çıktığı haliyle hâlâ biraz daha cilalı olduğunu not edin. Aynı içerik, orada biraz daha yüksek bir bitiş; burada ise belirgin biçimde daha fazla kontrol ve daha düşük işletme maliyeti.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li><strong>Zaten parasını ödediğiniz ajan üzerinde çalıştırın</strong> (ya da BYOK) — ayrı bir token tavanından kurtulmak için.</li>\n<li><strong>Taslağı ucuz bir modelde yapın, son hali güçlü bir modelde bitirin</strong> — maliyet/kalite ayarını her proje için siz kontrol edersiniz.</li>\n<li><strong>Satır içi düzenleme ve alan yorumlarını kullanın</strong> — tüm sayfayı yeniden üretmek yerine ucuz, cerrahi değişiklikler için.</li>\n<li><strong>Koda aktarın ya da Vercel/Cloudflare'e yayına alın</strong> — bitirdiğinizde doğrudan Paylaş üzerinden.</li>\n<li><strong>hyperframes becerisini deneyin</strong> — yalnızca statik sayfalara değil, harekete/videoya ihtiyacınız olduğunda.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Bu, kapalı bir bulut aracına kıyasla token'ları nasıl tasarruf ediyor?</strong>\nÜretim kendi ajanınız/aboneliğiniz ya da kendi API anahtarınız üzerinden çalışır, dolayısıyla tüketilecek ayrı, sayaca bağlı bir tasarım bütçesi yoktur — modeli ve maliyeti siz seçersiniz.</p>\n<p><strong>Çıktıyı kendi düzenleyicimde çalışmaya devam edebilir miyim?</strong>\nEvet — çıktı düzenlenebilir HTML/dosyalardır. Kaynağa tıklayıp VS Code, Cursor ya da herhangi bir düzenleyicide devam edin, ya da Vercel/Cloudflare Pages'e yayına alın.</p>\n<p><strong>Web sayfalarından fazlasını yapabilir mi?</strong>\nEvet — prototipler, desteler, görseller ve video (hyperframes hareket becerisi aracılığıyla), ayrıca geniş bir tasarım sistemleri kütüphanesi.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaklıdır ve yerelde çalıştırması ücretsizdir. Yalnızca bağladığınız ajan ve anahtarın model ve medya kullanımı için ödeme yaparsınız.</p>\n<hr>\n<p><em>Bu yazılı rehber Roy Shavit'in adım adım anlatımına dayanır. Yukarıdaki tam videoyu izleyin ve daha fazla pratik yapay zeka geliştirme içeriği için <a href=\"https://www.youtube.com/watch?v=17Wbq5r8tzA\">Roy Shavit'e abone olun</a>.</em></p>",
  },
};
